patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..aa1e5d48b407 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -46,6 +46,7 @@
 #include "llvm/Support/KnownBits.h"
 #include "llvm/Support/KnownFPClass.h"
 #include <algorithm>
+#include "llvm/Support/raw_ostream.h"
 #include <optional>
 using namespace llvm;
 using namespace llvm::PatternMatch;
@@ -1849,6 +1850,54 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  ? static_cast<Value *>(LHS)
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }
+  // Handle (fcmp pred X, C0) &&/|| (fcmp pred X, C1)
+  if (PredL == PredR && !(LHS->getFastMathFlags() != RHS->getFastMathFlags())) {
+    Value *X = nullptr;
+    const APFloat *C0 = nullptr, *C1 = nullptr;
+    CmpPredicate Pred;
+    // Match X, C0 and X, C1
+    if (match(LHS, m_FCmp(Pred, m_Value(X), m_APFloat(C0))) &&
+        Pred == PredL &&
+        match(RHS, m_FCmp(Pred, m_Specific(X), m_APFloat(C1)))) {
+      // Determine subset relationship.
+      APFloat::cmpResult R = C0->compare(*C1);
+      bool IsSubset = false;
+      bool IsSuperset = false;
+      switch (PredL) {
+      case FCmpInst::FCMP_OLT:
+      case FCmpInst::FCMP_OLE:
+      case FCmpInst::FCMP_ULT:
+      case FCmpInst::FCMP_ULE:
+        // For less-than predicates, set A = {x | x < C0} (or <=).
+        // A subset of B iff C0 <= C1 (or strict depending on predicate equality?)
+        // Since constants are exact, we can compare.
+        IsSubset = R == APFloat::cmpLessThan || R == APFloat::cmpEqual;
+        IsSuperset = R == APFloat::cmpGreaterThan || R == APFloat::cmpEqual;
+        break;
+      case FCmpInst::FCMP_OGT:
+      case FCmpInst::FCMP_OGE:
+      case FCmpInst::FCMP_UGT:
+      case FCmpInst::FCMP_UGE:
+        IsSubset = R == APFloat::cmpGreaterThan || R == APFloat::cmpEqual;
+        IsSuperset = R == APFloat::cmpLessThan || R == APFloat::cmpEqual;
+        break;
+      default:
+        break;
+      }
+      if (IsSubset) {
+        // LHS set is subset of RHS set.
+        return IsAnd ? LHS : RHS;
+      }
+      if (IsSuperset) {
+        // LHS set is superset of RHS set.
+        return IsAnd ? RHS : LHS;
+      }
+    }
+    // Match swapped constants: (fcmp pred C0, X) &&/|| (fcmp pred C1, X)
+    // For swapped constants, the predicate direction is reversed.
+    // Example: (C0 olt X) == (X ogt C0). We'll handle by converting predicate.
+    // For simplicity, skip for now.
+  }

   return nullptr;
 }

